// Devuelve presupuestos. Por defecto oculta los soft-deleted; con
// ?incluir_archivadas=1 los incluye pero relegados al final del orden.
// Filtros opcionales por query-string:
//   ?cliente=<texto>           (contains, case-insensitive)
//   ?estado=aceptado|en_espera
//   ?estado_entrega=pendiente|en_progreso|entregado
//   ?entorno=backoffice|app_cliente
//   ?quien_abona=yurest|cliente
//   ?incluir_archivadas=1
const wh = $('Webhook GET Presupuestos').first().json || {};
const q = wh.query || wh.params || {};
const verArch = String(q.incluir_archivadas || '') === '1';
const raw = ($input.all() || [])
  .map(i => i.json)
  .filter(x => x && x.id && (verArch || !x.deleted_at));
let out = raw;
if (q.cliente) {
  const needle = String(q.cliente).toLowerCase();
  out = out.filter(p => String(p.cliente||'').toLowerCase().includes(needle));
}
if (q.estado)          out = out.filter(p => p.estado === q.estado);
if (q.estado_entrega)  out = out.filter(p => p.estado_entrega === q.estado_entrega);
if (q.entorno)         out = out.filter(p => p.entorno === q.entorno);
if (q.quien_abona)     out = out.filter(p => p.quien_abona === q.quien_abona);
// Orden: vivos primero, archivados al final (para que no desplacen
// los vivos cuando verArch=true). Dentro de vivos: aceptados primero,
// luego en_espera; dentro por created_at desc.
out.sort((a, b) => {
  const ax = a.deleted_at ? 1 : 0;
  const bx = b.deleted_at ? 1 : 0;
  if (ax !== bx) return ax - bx;
  if (a.estado !== b.estado) return a.estado === 'aceptado' ? -1 : 1;
  const da = a.created_at ? new Date(a.created_at).getTime() : 0;
  const db = b.created_at ? new Date(b.created_at).getTime() : 0;
  return db - da;
});
// Totales agregados (útil para la UI sin recalcular) — sólo sobre
// presupuestos vivos, para que no sumen los archivados al ver todo.
const totales = out.filter(p => !p.deleted_at).reduce((acc, p) => {
  acc.horas_yurest  += Number(p.horas_yurest)  || 0;
  acc.horas_cliente += Number(p.horas_cliente) || 0;
  acc.coste_yurest  += Number(p.coste_yurest)  || 0;
  acc.coste_cliente += Number(p.coste_cliente) || 0;
  return acc;
}, { horas_yurest: 0, horas_cliente: 0, coste_yurest: 0, coste_cliente: 0 });
return [{ json: { presupuestos: out, totales } }];

// Acciones soportadas:
//   create         → alta de presupuesto
//   update         → edición de cualquier campo
//   archivar       → soft-delete (deleted_at=now)
//   reactivar      → deshace archivar
//   marcar_enviado → flip del flag enviado (true/false opcional, default true)
//   aceptar        → atajo: estado='aceptado'
//   entregar       → atajo: estado_entrega='entregado'
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || '').toLowerCase();
const p = b.presupuesto || {};
const now = new Date().toISOString();
const errores = [];
const VALID = ['create', 'update', 'archivar', 'reactivar', 'marcar_enviado', 'aceptar', 'entregar'];
if (!VALID.includes(action)) errores.push('action inválida: ' + action);
if (action !== 'create' && !p.id) errores.push('id obligatorio para ' + action);
if (p.id && !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(p.id)) {
  errores.push('id no es un UUID válido');
}

const ENTORNOS = ['backoffice', 'app_cliente'];
const QUIENES  = ['yurest', 'cliente'];
const ESTADOS  = ['aceptado', 'en_espera'];
const ENTREGAS = ['pendiente', 'en_progreso', 'entregado'];

function validaNumero(v, nombre, min, max) {
  if (v === undefined) return undefined;
  const n = +v;
  if (!Number.isFinite(n)) { errores.push(nombre + ' debe ser número'); return undefined; }
  if (n < min || n > max)  { errores.push(nombre + ' fuera de rango (' + min + '..' + max + ')'); return undefined; }
  return n;
}

let out = {};
if (action === 'create') {
  if (!p.cliente || !String(p.cliente).trim()) errores.push('cliente obligatorio');
  if (!p.desarrollo || !String(p.desarrollo).trim()) errores.push('desarrollo obligatorio');
  if (p.entorno && !ENTORNOS.includes(p.entorno)) errores.push('entorno debe ser backoffice|app_cliente');
  if (p.quien_abona && !QUIENES.includes(p.quien_abona)) errores.push('quien_abona debe ser yurest|cliente');
  if (p.estado && !ESTADOS.includes(p.estado)) errores.push('estado debe ser aceptado|en_espera');
  if (p.estado_entrega && !ENTREGAS.includes(p.estado_entrega)) errores.push('estado_entrega debe ser pendiente|en_progreso|entregado');
  const hy = validaNumero(p.horas_yurest,  'horas_yurest',  0, 10000);
  const hc = validaNumero(p.horas_cliente, 'horas_cliente', 0, 10000);
  const cy = validaNumero(p.coste_yurest,  'coste_yurest',  0, 99999999.99);
  const cc = validaNumero(p.coste_cliente, 'coste_cliente', 0, 99999999.99);
  // UUID aquí (igual que hardware/promociones) para que PostgREST tenga PK explícita.
  const _uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){ const r = Math.random()*16|0; return (c==='x'?r:(r&0x3)|0x8).toString(16); });
  out = {
    id: _uuid,
    cliente: String(p.cliente || '').trim(),
    entorno: p.entorno || 'backoffice',
    desarrollo: String(p.desarrollo || '').trim(),
    enviado: p.enviado === true,
    quien_abona: p.quien_abona || 'cliente',
    estado: p.estado || 'en_espera',
    horas_yurest:  hy !== undefined ? hy : 0,
    horas_cliente: hc !== undefined ? hc : 0,
    coste_yurest:  cy !== undefined ? cy : 0,
    coste_cliente: cc !== undefined ? cc : 0,
    estado_entrega: p.estado_entrega || 'pendiente',
    notas: p.notas != null ? String(p.notas) : null,
    contexto:                p.contexto                != null ? String(p.contexto)                : null,
    objetivo:                p.objetivo                != null ? String(p.objetivo)                : null,
    alcance:                 p.alcance                 != null ? String(p.alcance)                 : null,
    funcionamiento_esperado: p.funcionamiento_esperado != null ? String(p.funcionamiento_esperado) : null,
    entregables:             p.entregables             != null ? String(p.entregables)             : null,
    presupuesto_detalle:     p.presupuesto_detalle     != null ? String(p.presupuesto_detalle)     : null,
    aprobacion:              p.aprobacion              != null ? String(p.aprobacion)              : null,
    created_by: p.created_by ? String(p.created_by) : null,
    created_at: now,
    updated_at: now
  };
} else if (action === 'update') {
  out.id = p.id;
  if (p.cliente !== undefined) {
    const v = p.cliente == null ? '' : String(p.cliente).trim();
    if (!v) errores.push('cliente no puede ser vacío');
    else out.cliente = v;
  }
  if (p.desarrollo !== undefined) {
    const v = p.desarrollo == null ? '' : String(p.desarrollo).trim();
    if (!v) errores.push('desarrollo no puede ser vacío');
    else out.desarrollo = v;
  }
  if (p.entorno !== undefined) {
    if (!ENTORNOS.includes(p.entorno)) errores.push('entorno debe ser backoffice|app_cliente');
    else out.entorno = p.entorno;
  }
  if (p.quien_abona !== undefined) {
    if (!QUIENES.includes(p.quien_abona)) errores.push('quien_abona debe ser yurest|cliente');
    else out.quien_abona = p.quien_abona;
  }
  if (p.estado !== undefined) {
    if (!ESTADOS.includes(p.estado)) errores.push('estado debe ser aceptado|en_espera');
    else out.estado = p.estado;
  }
  if (p.estado_entrega !== undefined) {
    if (!ENTREGAS.includes(p.estado_entrega)) errores.push('estado_entrega inválido');
    else out.estado_entrega = p.estado_entrega;
  }
  if (p.enviado !== undefined)       out.enviado       = !!p.enviado;
  if (p.horas_yurest  !== undefined) { const n = validaNumero(p.horas_yurest,  'horas_yurest',  0, 10000); if (n !== undefined) out.horas_yurest  = n; }
  if (p.horas_cliente !== undefined) { const n = validaNumero(p.horas_cliente, 'horas_cliente', 0, 10000); if (n !== undefined) out.horas_cliente = n; }
  if (p.coste_yurest  !== undefined) { const n = validaNumero(p.coste_yurest,  'coste_yurest',  0, 99999999.99); if (n !== undefined) out.coste_yurest  = n; }
  if (p.coste_cliente !== undefined) { const n = validaNumero(p.coste_cliente, 'coste_cliente', 0, 99999999.99); if (n !== undefined) out.coste_cliente = n; }
  if (p.notas !== undefined) out.notas = p.notas != null ? String(p.notas) : null;
  // Secciones estructuradas del presupuesto (todas texto libre). Si el
  // campo viene undefined NO se toca; si viene null se persiste null.
  const SECCIONES = ['contexto','objetivo','alcance','funcionamiento_esperado','entregables','presupuesto_detalle','aprobacion'];
  for (const k of SECCIONES) {
    if (p[k] !== undefined) out[k] = p[k] != null ? String(p[k]) : null;
  }
  out.updated_at = now;
} else if (action === 'archivar') {
  out = { id: p.id, deleted_at: now, updated_at: now };
} else if (action === 'reactivar') {
  out = { id: p.id, deleted_at: null, updated_at: now };
} else if (action === 'marcar_enviado') {
  out = { id: p.id, enviado: p.enviado === false ? false : true, updated_at: now };
} else if (action === 'aceptar') {
  out = { id: p.id, estado: 'aceptado', updated_at: now };
} else if (action === 'entregar') {
  out = { id: p.id, estado_entrega: 'entregado', updated_at: now };
}

Object.keys(out).forEach(k => { if (out[k] === undefined) delete out[k]; });

if (errores.length > 0) {
  return [{ json: { __error: true, __errores: errores, __action: action, __method: 'POST', __qs: 'on_conflict=id' } }];
}
const _method = (action === 'create') ? 'POST' : 'PATCH';
const _qs = (action === 'create') ? 'on_conflict=id' : ('id=eq.' + encodeURIComponent(p.id || ''));
return [{ json: Object.assign({}, out, { __method: _method, __qs: _qs }) }];

// Normaliza la salida PostgREST al shape único del frontend:
//   { success, presupuesto, errores }
const prep = $('Preparar').first().json || {};
if (prep.__error) {
  return [{ json: { success: false, presupuesto: null, errores: prep.__errores || ['validación falló'] } }];
}
const items = $input.all() || [];
const errores = [];
let rows = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  if (j.code && j.message && !j.id) {
    errores.push(j.message + (j.details ? ' (' + j.details + ')' : ''));
    continue;
  }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.id) rows.push(j);
  if (Array.isArray(j.data)) rows = rows.concat(j.data);
}
if (rows.length === 0 && errores.length === 0) errores.push('PostgREST devolvió 0 filas');
return [{ json: {
  success: rows.length > 0,
  presupuesto: rows[0] || null,
  errores
} }];
